// ============================================
// Wallet Manager
// ============================================
class WalletManager {
    constructor() {
        this.wallets = new Map();
        this.providers = new Map();
    }

    getProvider(networkName) {
        if (!this.providers.has(networkName)) {
            const rpcUrl = config.networks[networkName];
            if (!rpcUrl) {
                throw new Error(`Unknown network: ${networkName}`);
            }
            const provider = new ethers.JsonRpcProvider(rpcUrl);
            this.providers.set(networkName, provider);
        }
        return this.providers.get(networkName);
    }

    addWallet(name, privateKey, networkName = config.defaultNetwork) {
        if (!privateKey || privateKey === 'YOUR_PRIVATE_KEY_HERE') {
            throw new Error('Invalid private key. Set your private key in the .env file.');
        }
        const provider = this.getProvider(networkName);
        const wallet = new ethers.Wallet(privateKey, provider);
        this.wallets.set(name, { wallet, networkName });
        console.log(`Wallet "${name}" added: ${wallet.address} on ${networkName}`);
        return wallet.address;
    }

    getWallet(name) {
        const entry = this.wallets.get(name);
        if (!entry) {
            throw new Error(`Wallet "${name}" not found. Add it first using addWallet().`);
        }
        return entry.wallet;
    }

    getWalletInfo(name) {
        const entry = this.wallets.get(name);
        if (!entry) {
            throw new Error(`Wallet "${name}" not found.`);
        }
        return {
            address: entry.wallet.address,
            network: entry.networkName
        };
    }

    listWallets() {
        const walletList = [];
        for (const [name, entry] of this.wallets) {
            walletList.push({
                name,
                address: entry.wallet.address,
                network: entry.networkName
            });
        }
        return walletList;
    }
}

// ============================================
// Transaction Service
// ============================================
class TransactionService {
    constructor(walletManager) {
        this.walletManager = walletManager;
        this.transactionHistory = [];
    }

    async getBalance(walletName) {
        const wallet = this.walletManager.getWallet(walletName);
        const balance = await wallet.provider.getBalance(wallet.address);
        return {
            address: wallet.address,
            balanceWei: balance.toString(),
            balanceEth: ethers.formatEther(balance)
        };
    }

    async getBalanceOfAddress(address, networkName = config.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        const balance = await provider.getBalance(address);
        return {
            address,
            balanceWei: balance.toString(),
            balanceEth: ethers.formatEther(balance)
        };
    }

    async estimateGas(walletName, toAddress, amountEth) {
        const wallet = this.walletManager.getWallet(walletName);
        const tx = {
            to: toAddress,
            value: ethers.parseEther(amountEth.toString())
        };
        const gasEstimate = await wallet.provider.estimateGas({
            ...tx,
            from: wallet.address
        });
        const feeData = await wallet.provider.getFeeData();
        const estimatedCostWei = gasEstimate * (feeData.gasPrice || 0n);
        return {
            gasEstimate: gasEstimate.toString(),
            gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : 'N/A',
            maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei' : 'N/A',
            maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei' : 'N/A',
            estimatedCostEth: ethers.formatEther(estimatedCostWei)
        };
    }

    async sendETH(walletName, toAddress, amountEth, options = {}) {
        const wallet = this.walletManager.getWallet(walletName);

        // Validate address
        if (!ethers.isAddress(toAddress)) {
            throw new Error(`Invalid Ethereum address: ${toAddress}`);
        }

        // Build transaction
        const tx = {
            to: toAddress,
            value: ethers.parseEther(amountEth.toString()),
            ...options
        };

        // Get nonce if not provided
        if (!tx.nonce) {
            tx.nonce = await wallet.getNonce();
        }

        console.log(`Sending ${amountEth} ETH from ${wallet.address} to ${toAddress}...`);

        // Sign and send transaction
        const txResponse = await wallet.sendTransaction(tx);
        console.log(`Transaction sent! Hash: ${txResponse.hash}`);

        // Wait for confirmation
        const receipt = await txResponse.wait(1);
        console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

        const txRecord = {
            type: 'ETH_TRANSFER',
            hash: txResponse.hash,
            from: wallet.address,
            to: toAddress,
            value: amountEth,
            blockNumber: receipt.blockNumber,
            gasUsed: receipt.gasUsed.toString(),
            status: receipt.status === 1 ? 'SUCCESS' : 'FAILED',
            timestamp: new Date().toISOString()
        };

        this.transactionHistory.push(txRecord);
        return txRecord;
    }

    async sendETHWithRetry(walletName, toAddress, amountEth, maxRetries = 3) {
        let lastError;
        for (let attempt = 1; attempt <= maxRetries; attempt++) {
            try {
                console.log(`Attempt ${attempt}/${maxRetries}...`);
                return await this.sendETH(walletName, toAddress, amountEth);
            } catch (error) {
                lastError = error;
                console.error(`Attempt ${attempt} failed: ${error.message}`);
                if (attempt < maxRetries) {
                    const delay = attempt * 2000;
                    console.log(`Retrying in ${delay / 1000}s...`);
                    await new Promise(resolve => setTimeout(resolve, delay));
                }
            }
        }
        throw new Error(`Transaction failed after ${maxRetries} attempts: ${lastError.message}`);
    }

    getTransactionHistory() {
        return this.transactionHistory;
    }
}

