class SmartContractService {
    constructor(walletManager) {
        this.walletManager = walletManager;
        this.contracts = new Map();
    }

    loadContract(name, contractAddress, abi, walletName) {
        if (!ethers.isAddress(contractAddress)) {
            throw new Error(`Invalid contract address: ${contractAddress}`);
        }

        const wallet = this.walletManager.getWallet(walletName);
        const contract = new ethers.Contract(contractAddress, abi, wallet);

        this.contracts.set(name, {
            contract,
            address: contractAddress,
            walletName
        });

        console.log(`Contract "${name}" loaded at ${contractAddress}`);
        return contract;
    }

    loadReadOnlyContract(name, contractAddress, abi, networkName = config.defaultNetwork) {
        if (!ethers.isAddress(contractAddress)) {
            throw new Error(`Invalid contract address: ${contractAddress}`);
        }

        const provider = this.walletManager.getProvider(networkName);
        const contract = new ethers.Contract(contractAddress, abi, provider);

        this.contracts.set(name, {
            contract,
            address: contractAddress,
            walletName: null,
            readOnly: true
        });

        console.log(`Read-only contract "${name}" loaded at ${contractAddress}`);
        return contract;
    }

    getContract(name) {
        const entry = this.contracts.get(name);
        if (!entry) {
            throw new Error(`Contract "${name}" not found. Load it first.`);
        }
        return entry.contract;
    }

    async callReadFunction(contractName, functionName, ...args) {
        const contract = this.getContract(contractName);
        if (!contract[functionName]) {
            throw new Error(`Function "${functionName}" not found on contract "${contractName}"`);
        }
        console.log(`Calling ${contractName}.${functionName}(${args.join(', ')})...`);
        const result = await contract[functionName](...args);
        console.log(`Result: ${result}`);
        return result;
    }

    async callWriteFunction(contractName, functionName, ...args) {
        const contract = this.getContract(contractName);
        if (!contract[functionName]) {
            throw new Error(`Function "${functionName}" not found on contract "${contractName}"`);
        }

        console.log(`Sending tx: ${contractName}.${functionName}(${args.join(', ')})...`);
        const tx = await contract[functionName](...args);
        console.log(`Transaction sent! Hash: ${tx.hash}`);

        const receipt = await tx.wait(1);
        console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

        return {
            hash: tx.hash,
            blockNumber: receipt.blockNumber,
            gasUsed: receipt.gasUsed.toString(),
            status: receipt.status === 1 ? 'SUCCESS' : 'FAILED',
            logs: receipt.logs
        };
    }

    async callWriteFunctionWithValue(contractName, functionName, ethValue, ...args) {
        const contract = this.getContract(contractName);
        if (!contract[functionName]) {
            throw new Error(`Function "${functionName}" not found on contract "${contractName}"`);
        }

        console.log(`Sending tx with ${ethValue} ETH: ${contractName}.${functionName}(${args.join(', ')})...`);
        const tx = await contract[functionName](...args, {
            value: ethers.parseEther(ethValue.toString())
        });
        console.log(`Transaction sent! Hash: ${tx.hash}`);

        const receipt = await tx.wait(1);
        console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

        return {
            hash: tx.hash,
            blockNumber: receipt.blockNumber,
            gasUsed: receipt.gasUsed.toString(),
            status: receipt.status === 1 ? 'SUCCESS' : 'FAILED',
            logs: receipt.logs
        };
    }

    async listenToEvents(contractName, eventName, callback) {
        const contract = this.getContract(contractName);
        contract.on(eventName, (...args) => {
            const event = args[args.length - 1];
            console.log(`Event "${eventName}" detected in tx ${event.log.transactionHash}`);
            callback(...args);
        });
        console.log(`Listening for "${eventName}" events on contract "${contractName}"...`);
    }

    async getEvents(contractName, eventName, fromBlock = 0, toBlock = 'latest') {
        const contract = this.getContract(contractName);
        const filter = contract.filters[eventName]();
        const events = await contract.queryFilter(filter, fromBlock, toBlock);
        return events.map(event => ({
            blockNumber: event.blockNumber,
            transactionHash: event.transactionHash,
            args: event.args
        }));
    }
}

